const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let rnd = '';
for (let i = 0; i < 12; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
const runId = 'run-' + Date.now().toString(36) + rnd;

const catalogues = msg.data?.catalogues || [];
const catNames = catalogues.map(c => c.catalogName).filter(Boolean);
const now = new Date();
const nowISO = now.toISOString();
const nowShort = nowISO.replace('T', ' ').slice(0, 19);

function resolvePath(obj, path) {
    if (!path || !obj) return obj;
    const parts = path.split('.');
    let cur = obj;
    for (const p of parts) {
        if (cur == null || typeof cur !== 'object') return undefined;
        cur = cur[p];
    }
    return cur;
}

function extractEntries(data, rootPath) {
    if (!data) return [];
    if (rootPath) {
        const resolved = resolvePath(data, rootPath);
        if (Array.isArray(resolved)) return resolved;
        if (resolved && typeof resolved === 'object') return [resolved];
    }
    if (Array.isArray(data)) return data;
    if (data['dcat:dataset'] && Array.isArray(data['dcat:dataset'])) return data['dcat:dataset'];
    if (data.dataset && Array.isArray(data.dataset)) return data.dataset;
    if (data.datasets && Array.isArray(data.datasets)) return data.datasets;
    if (data.data && Array.isArray(data.data)) return data.data;
    if (data.results && Array.isArray(data.results)) return data.results;
    if (data.result && data.result.results && Array.isArray(data.result.results)) return data.result.results;
    if (data.items && Array.isArray(data.items)) return data.items;
    if (data.records && Array.isArray(data.records)) return data.records;
    if (data.entries && Array.isArray(data.entries)) return data.entries;
    if (data.assets && Array.isArray(data.assets)) return data.assets;
    if (data.catalogs && Array.isArray(data.catalogs)) return data.catalogs;
    if (data.title || data.name || data.identifier || data['@type']) return [data];
    if (data._id || data.requestId != null || data.companyDetails) return [data];
    const skipKeys = ['auditInfo','approveInfo','decisionHistory','errors','warnings','logs'];
    for (const key of Object.keys(data)) {
        if (Array.isArray(data[key]) && data[key].length > 0 && typeof data[key][0] === 'object' && !skipKeys.includes(key)) return data[key];
    }
    return [data];
}

function extractName(entry, nameField) {
    if (!entry || typeof entry !== 'object') return 'Unknown Asset';
    if (nameField) { const v = resolvePath(entry, nameField); if (v && typeof v === 'string' && v.trim()) return v; }
    const cands = ['title','name','catalogName','label','displayName','companyName','organisationName','organization','fullName','shortName','legalName','tradingName','firma'];
    for (const f of cands) { if (entry[f] && typeof entry[f] === 'string' && entry[f].trim()) return entry[f]; }
    const cd = entry.companyDetails;
    if (cd && typeof cd === 'object') {
        if (cd['A.1.1.1'] && typeof cd['A.1.1.1'] === 'string') return cd['A.1.1.1'];
        if (cd['A.2.1.1'] && typeof cd['A.2.1.1'] === 'string') return cd['A.2.1.1'];
        for (const f of cands) { if (cd[f] && typeof cd[f] === 'string' && cd[f].trim()) return cd[f]; }
    }
    if (entry.createdBy && entry.createdBy.fullName && typeof entry.createdBy.fullName === 'string') return entry.createdBy.fullName;
    for (const key of Object.keys(entry)) {
        const nested = entry[key];
        if (nested && typeof nested === 'object' && !Array.isArray(nested)) {
            for (const f of cands) { if (nested[f] && typeof nested[f] === 'string' && nested[f].trim()) return nested[f]; }
        }
    }
    for (const key of Object.keys(entry)) {
        const val = entry[key];
        if (typeof val === 'string' && val.length > 2 && val.length < 200 && !/^[\d\-:.TZ]+$/.test(val) && !/^[0-9a-f]{24}$/i.test(val) && !key.startsWith('_')) return val;
    }
    return 'Unknown Asset';
}

function extractId(entry, idField) {
    if (idField) { const v = resolvePath(entry, idField); if (v) return String(v); }
    return String(entry.identifier || entry.id || entry._id || entry.requestId || entry.uuid || ('remote-' + Math.random().toString(36).slice(2, 10)));
}

function extractType(entry, typeField) {
    if (typeField) { const v = resolvePath(entry, typeField); if (v) return String(v); }
    const cd = entry.companyDetails;
    return String(entry['@type'] || entry.type || entry.assetType || (cd && cd['A.1.1.0']) || (cd && cd['A.2.1.4']) || 'dcat:Dataset');
}

// ── FR-ACM-05: Crawling Reference helpers ─────────────────────────────────────
const REFERENCE_FIELDS = [
  'dcat:qualifiedRelation',
  'dcat:Relationship',
  'dcat:source',
  'prov:wasDerivedFrom',
  'dct:references',
  'dct:relation',
  'qualifiedRelation',
  'relation',
  'references',
  'source'
];

function normalizeRefUri(v) {
  if (v == null) return null;
  if (typeof v === 'string') {
    const s = v.trim();
    if (!s) return null;
    if (/^https?:\/\//i.test(s) || /^did:[a-z0-9]+:/i.test(s) || /^urn:/i.test(s)) return s;
    return null;
  }
  if (typeof v === 'object') {
    if (v['@id']) return normalizeRefUri(v['@id']);
    if (v.href) return normalizeRefUri(v.href);
    if (v.id && typeof v.id === 'string') return normalizeRefUri(v.id);
    if (v.hasTarget) return normalizeRefUri(v.hasTarget);
    if (v.target) return normalizeRefUri(v.target);
  }
  return null;
}

function extractReferencesFromEntry(entry) {
  if (!entry || typeof entry !== 'object') return [];
  const refs = [];
  for (const field of REFERENCE_FIELDS) {
    const v = entry[field];
    if (v == null) continue;
    const arr = Array.isArray(v) ? v : [v];
    for (const item of arr) {
      const uri = normalizeRefUri(item);
      if (uri) refs.push({ field: field, uri: uri });
    }
  }
  if (Array.isArray(entry.links)) {
    for (const l of entry.links) {
      if (l && typeof l.href === 'string') {
        const uri = normalizeRefUri(l.href);
        if (uri) refs.push({ field: 'links', uri: uri, rel: l.rel || '' });
      }
    }
  }
  return refs;
}

function entryMatchesUri(entry, uri) {
  if (!entry || typeof entry !== 'object' || !uri) return false;
  const candidates = [
    entry['@id'], entry.id, entry.identifier, entry._id,
    entry.uri, entry.url, entry.did, entry.canonicalUri
  ].filter(Boolean).map(String);
  return candidates.indexOf(uri) !== -1;
}
// ── /FR-ACM-05 helpers ────────────────────────────────────────────────────────

const provenance = [];
const logs = [];
const assetDetails = [];
const lcDocs = [];
let assetCounter = 0;

for (const cat of catalogues) {
    const catName = cat.catalogName || cat.uniqueId || 'Unknown';
    const catId = cat.uniqueId || cat.catalogId || '';
    const isCrawlOnly = cat._crawlOnly === true;
    if (isCrawlOnly) {
        logs.push({ runId, assetId: '', level: 'info', message: 'Catalogue tagged crawl-only, skipping full import: ' + catName, catalogue: catName, timestamp: nowISO });
        continue;
    }
    const strategy = cat.strategy || 'none';
    const rootPath = cat.responseRootPath || '';
    const idField = cat.responseAssetIdField || '';
    const nameField = cat.responseAssetNameField || '';
    const typeField = cat.responseAssetTypeField || '';
    const typeMapping = Array.isArray(cat.typeMapping) ? cat.typeMapping : [];
    const sourceData = cat.sourceData || null;
    let entries = [];
    if (sourceData) {
        entries = extractEntries(sourceData, rootPath);
        logs.push({ runId, assetId: '', level: 'info', message: 'Extracted ' + entries.length + ' entries from sourceData', catalogue: catName, timestamp: nowISO });
    }

    for (let i = 0; i < entries.length; i++) {
        assetCounter++;
        const entry = entries[i];
        if (!entry || typeof entry !== 'object') continue;
        const assetId = 'asset-' + runId + '-' + assetCounter;
        const lcId = 'lc-' + runId + '-' + assetCounter;
        const rawId = extractId(entry, idField);
        const assetName = extractName(entry, nameField);
        const assetType = extractType(entry, typeField);
        const mapRow = typeMapping.find(m => m && m.remoteType === assetType);
        const localTypeId = mapRow && mapRow.localTypeId ? String(mapRow.localTypeId) : '';
        const domain = entry.domain || entry.theme || entry.category || catName;

        assetDetails.push({ assetId: assetId, title: assetName, catalogue: catName, status: 'success', strategy: strategy, sourceId: rawId, localTypeId: localTypeId });
        lcDocs.push({
            uniqueId: lcId,
            id: lcId,
            assets: assetName,
            title: assetName,
            type: assetType,
            localTypeId: localTypeId,
            name: catName,
            domain: domain,
            updated: nowShort,
            integrationStatus: 'Active',
            sourceCatalogue: catName,
            sourceCatalogueId: catId,
            harvestRunId: runId,
            remoteAssetId: rawId,
            originalForm: entry,
            transformedForm: null,
            sourceAssetId: rawId,
            harvestedAt: nowISO,
            createdAt: nowISO
        });
        provenance.push({ runId: runId, assetId: assetId, title: assetName, catalogue: catName, action: 'imported', strategy: strategy, timestamp: nowISO, status: 'success', sourceId: rawId });
        logs.push({ runId: runId, assetId: assetId, level: 'info', message: 'Imported: ' + assetName, catalogue: catName, timestamp: nowISO });
    }

    logs.push({ runId: runId, assetId: '', level: 'info', message: 'Harvest completed for ' + catName + ': ' + entries.length + ' entries processed', catalogue: catName, timestamp: nowISO });
}

// ── FR-ACM-05: Crawl references (BFS, max depth 3, cycle detection) ──────────
const resolveReferences = !!(msg.data?.scope && msg.data.scope.resolveReferences);
let crawlStats = { enabled: resolveReferences, referencesFound: 0, crawledAssets: 0, unresolved: 0, maxDepthReached: 0 };

if (resolveReferences) {
    const crawlIndex = [];
    for (const cat of catalogues) {
        const catName = cat.catalogName || cat.uniqueId || 'Unknown';
        const catId = cat.uniqueId || cat.catalogId || '';
        const rootPath = cat.responseRootPath || '';
        const entries = cat.sourceData ? extractEntries(cat.sourceData, rootPath) : [];
        for (const entry of entries) {
            crawlIndex.push({
                entry,
                catName, catId,
                strategy: cat.strategy || 'none',
                idField: cat.responseAssetIdField || '',
                nameField: cat.responseAssetNameField || '',
                typeField: cat.responseAssetTypeField || '',
                typeMapping: Array.isArray(cat.typeMapping) ? cat.typeMapping : [],
                crawlOnly: cat._crawlOnly === true
            });
        }
    }

    const MAX_DEPTH = 3;
    const visitedUris = new Set();
    const visitedAssetIds = new Set(lcDocs.map(d => d.id));

    const queue = [];
    for (const lcDoc of lcDocs) {
        queue.push({ entry: lcDoc.originalForm, lcId: lcDoc.id, depth: 1 });
    }

    while (queue.length > 0) {
        const { entry, lcId, depth } = queue.shift();
        if (depth > MAX_DEPTH) continue;
        crawlStats.maxDepthReached = Math.max(crawlStats.maxDepthReached, depth);

        const refs = extractReferencesFromEntry(entry);
        for (const ref of refs) {
            crawlStats.referencesFound++;
            if (visitedUris.has(ref.uri)) continue;
            visitedUris.add(ref.uri);

            const hit = crawlIndex.find(row => entryMatchesUri(row.entry, ref.uri));
            if (!hit) {
                crawlStats.unresolved++;
                provenance.push({
                    runId, assetId: lcId, action: 'crawl-unresolved',
                    referenceUri: ref.uri, referenceField: ref.field,
                    timestamp: nowISO, status: 'warning',
                    message: 'Reference target not found in any supplied catalogue'
                });
                logs.push({
                    runId, assetId: lcId, level: 'warn',
                    message: 'Unresolved cross-catalogue reference: ' + ref.uri + ' (field=' + ref.field + ')',
                    catalogue: '', timestamp: nowISO
                });
                continue;
            }

            assetCounter++;
            const newAssetId = 'asset-' + runId + '-' + assetCounter;
            const newLcId = 'lc-' + runId + '-' + assetCounter;
            if (visitedAssetIds.has(newLcId)) continue;
            visitedAssetIds.add(newLcId);

            const rawId = extractId(hit.entry, hit.idField);
            const assetName = extractName(hit.entry, hit.nameField);
            const assetType = extractType(hit.entry, hit.typeField);
            const mapRow = hit.typeMapping.find(m => m && m.remoteType === assetType);
            const localTypeId = mapRow && mapRow.localTypeId ? String(mapRow.localTypeId) : '';
            const domain = hit.entry.domain || hit.entry.theme || hit.entry.category || hit.catName;

            assetDetails.push({ assetId: newAssetId, title: assetName, catalogue: hit.catName, status: 'success', strategy: hit.strategy, sourceId: rawId, localTypeId: localTypeId, crawled: true });
            const newLcDoc = {
                uniqueId: newLcId,
                id: newLcId,
                assets: assetName,
                title: assetName,
                type: assetType,
                localTypeId: localTypeId,
                name: hit.catName,
                domain: domain,
                updated: nowShort,
                integrationStatus: 'Active',
                sourceCatalogue: hit.catName,
                sourceCatalogueId: hit.catId,
                harvestRunId: runId,
                remoteAssetId: rawId,
                originalForm: hit.entry,
                transformedForm: null,
                sourceAssetId: rawId,
                harvestedAt: nowISO,
                createdAt: nowISO,
                crawledFrom: lcId,
                crawlDepth: depth,
                crawlReferenceUri: ref.uri,
                crawlReferenceField: ref.field
            };
            lcDocs.push(newLcDoc);
            provenance.push({ runId, assetId: newAssetId, title: assetName, catalogue: hit.catName, action: 'crawled', strategy: hit.strategy, timestamp: nowISO, status: 'success', sourceId: rawId, crawledFrom: lcId, crawlDepth: depth });
            logs.push({ runId, assetId: newAssetId, level: 'info', message: 'Crawled (depth=' + depth + '): ' + assetName + ' from ' + hit.catName + ' (ref=' + ref.uri + ')', catalogue: hit.catName, timestamp: nowISO });
            crawlStats.crawledAssets++;

            if (depth + 1 <= MAX_DEPTH) {
                queue.push({ entry: hit.entry, lcId: newLcId, depth: depth + 1 });
            }
        }
    }

    logs.push({ runId, assetId: '', level: 'info', message: 'Crawl complete: ' + crawlStats.crawledAssets + ' assets crawled, ' + crawlStats.unresolved + ' unresolved, max depth ' + crawlStats.maxDepthReached, catalogue: '', timestamp: nowISO });
}
// ── /FR-ACM-05 crawl block ───────────────────────────────────────────────────

const successCount = assetDetails.filter(a => a.status === 'success').length;
const errorCount = assetDetails.filter(a => a.status === 'error').length;

const run = {
    uniqueId: runId,
    catalogueName: catNames.filter(n => !catalogues.find(c => c.catalogName === n && c._crawlOnly)).join(', ') || 'Harvest',
    scope: msg.data?.scope || {},
